import type { ReactNode } from "react";
import { cn } from "@/lib/utils";

import PrivacyPolicyPage, { PRIVACY_CLAUSES } from "./privacy/page";

const LEGAL_PAGES = ["Privacy"] as const;

const CORNER_POSITIONS = {
	topLeft: "-top-2 -left-2",
	topRight: "-top-2 -right-2",
	bottomLeft: "-bottom-2 -left-2",
	bottomRight: "-right-2 -bottom-2",
} as const;

function CornerMark({ position }: { position: keyof typeof CORNER_POSITIONS }) {
	return (
		<span
			aria-hidden="true"
			className={cn(
				"pointer-events-none absolute z-10 flex size-4 items-center justify-center text-border",
				CORNER_POSITIONS[position],
			)}
		>
			<span className="absolute h-px w-full bg-current" />
			<span className="absolute h-full w-px bg-current" />
		</span>
	);
}

function LegalNavigation() {
	return (
		<nav aria-label="Legal" className="py-8 md:sticky md:top-8 md:py-12">
			<p className="font-mono text-[10px] text-muted-foreground uppercase tracking-[0.32em]">
				Legal
			</p>
			<ul className="mt-4 flex flex-wrap gap-1 md:mt-6 md:flex-col md:flex-nowrap md:gap-0.5">
				{LEGAL_PAGES.map((item) => {
					const isActive = item === "Privacy";

					return (
						<li className="md:w-full" key={item}>
							<span
								aria-current={isActive ? "page" : undefined}
								className={cn(
									"relative flex items-center rounded-sm px-3 py-2 font-mono text-[13px] tracking-tight md:rounded-none md:py-1.5 md:pr-2 md:pl-4",
									isActive
										? "bg-primary/10 text-primary before:absolute before:inset-y-0 before:left-0 before:hidden before:w-px before:bg-primary md:before:block"
										: "text-muted-foreground",
								)}
							>
								{item}
							</span>
							{isActive ? (
								<ol className="mt-3 ml-4 hidden flex-col gap-0.5 md:flex">
									{PRIVACY_CLAUSES.map((clause) => (
										<li key={clause.id}>
											<a
												className="block py-1.5 text-muted-foreground text-xs leading-snug transition-colors hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/50"
												href={`#${clause.id}`}
											>
												{clause.title}
											</a>
										</li>
									))}
								</ol>
							) : null}
						</li>
					);
				})}
			</ul>
		</nav>
	);
}

export interface LegalLayoutProps {
	children?: ReactNode;
}

export default function LegalLayout({
	children = <PrivacyPolicyPage />,
}: LegalLayoutProps) {
	return (
		<main className="min-h-svh bg-background px-4 py-12 text-foreground sm:px-6 lg:px-8 lg:py-16">
			<div className="relative mx-auto w-full max-w-6xl border border-border border-dashed">
				<CornerMark position="topLeft" />
				<CornerMark position="topRight" />
				<CornerMark position="bottomLeft" />
				<CornerMark position="bottomRight" />

				<div className="grid grid-cols-1 md:grid-cols-[12rem_minmax(0,1fr)]">
					<aside className="border-border border-b border-dashed px-6 md:border-r md:border-b-0 md:px-5">
						<LegalNavigation />
					</aside>
					<div className="min-w-0 px-6 py-10 md:px-10 md:py-12 lg:px-14">
						{children}
					</div>
				</div>
			</div>
		</main>
	);
}

import type { ReactNode } from "react";
import { Separator } from "@/components/ui/separator";

export interface LegalClause {
	id: string;
	title: string;
	body: ReactNode;
}

export const PRIVACY_CLAUSES = [
	{
		id: "information-we-collect",
		title: "Information we collect",
		body: (
			<p>
				We collect limited technical and usage information such as page views,
				interaction events, browser and device metadata, and referral
				information. This data helps us understand how the site is used and
				where it can be improved.
			</p>
		),
	},
	{
		id: "analytics-tools",
		title: "Analytics tools",
		body: (
			<p>
				We use privacy-conscious analytics to understand traffic and product
				usage patterns. If your browser blocks analytics scripts, the
				corresponding data is not collected.
			</p>
		),
	},
	{
		id: "how-we-use-data",
		title: "How we use data",
		body: (
			<ul>
				<li>Operate, secure, and improve the product.</li>
				<li>Understand which features are useful to visitors.</li>
				<li>Diagnose errors and monitor performance.</li>
			</ul>
		),
	},
	{
		id: "cookies-and-local-storage",
		title: "Cookies and local storage",
		body: (
			<p>
				We use local storage to remember preferences such as your theme and
				interface settings. Analytics providers may set their own cookies, which
				you can clear through your browser settings.
			</p>
		),
	},
	{
		id: "your-choices",
		title: "Your choices",
		body: (
			<p>
				You can opt out by blocking analytics in your browser or by using a
				browser with privacy protections enabled. Contact us if you need help
				with information you have submitted.
			</p>
		),
	},
	{
		id: "changes",
		title: "Changes",
		body: (
			<p>
				We may update this policy as our services change. The last updated date
				above reflects the most recent revision.
			</p>
		),
	},
] satisfies readonly LegalClause[];

export default function PrivacyPolicyPage() {
	return (
		<article className="max-w-2xl">
			<h1 className="text-balance font-semibold text-3xl text-foreground tracking-tight md:text-4xl">
				Privacy Policy
			</h1>
			<p className="mt-3 text-[12px] text-muted-foreground">
				Last updated July 21, 2026
			</p>
			<p className="mt-6 text-[14px] text-muted-foreground leading-relaxed">
				How we handle analytics and basic usage data on this website.
			</p>

			<ol className="mt-10 flex flex-col gap-10">
				{PRIVACY_CLAUSES.map((clause, index) => (
					<li className="scroll-mt-20" id={clause.id} key={clause.id}>
						<h2 className="font-semibold text-[15px] text-foreground tracking-tight">
							<span className="mr-3 text-muted-foreground tabular-nums">
								{String(index + 1).padStart(2, "0")}
							</span>
							{clause.title}
						</h2>
						<div className="mt-3 ml-9 flex flex-col gap-3 text-[14px] text-muted-foreground leading-relaxed [&_strong]:font-medium [&_strong]:text-foreground [&_ul]:flex [&_ul]:list-disc [&_ul]:flex-col [&_ul]:gap-1.5 [&_ul]:pl-5">
							{clause.body}
						</div>
					</li>
				))}
			</ol>

			<Separator className="mt-16" />
			<section className="pt-8">
				<h2 className="font-semibold text-[15px] text-foreground tracking-tight">
					Contact
				</h2>
				<p className="mt-3 max-w-2xl text-[14px] text-muted-foreground leading-relaxed">
					For privacy-related questions, exports, or deletion requests, contact
					us at{" "}
					<a
						className="rounded-sm font-medium text-foreground underline decoration-border underline-offset-4 transition-colors hover:text-primary focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/50"
						href="mailto:privacy@example.com"
					>
						privacy@example.com
					</a>
					.
				</p>
			</section>
		</article>
	);
}
